class Solution {
public:
    int numWays(int steps, int arrLen) {
        int MOD = 1e9 + 7;
        int dp[steps + 1][arrLen * 2 + 1];
        for (int i = 0; i <= steps; i++) {
            dp[i][arrLen] = 1;
        }
        for (int i = 1; i <= steps; i++) {
            for (int j = arrLen - 1; j >= 1; j--) {
                dp[i][j] = (dp[i - 1][j + 1] + dp[i - 1][j - 1]) % MOD;
            }
        }
        int res = 0;
        for (int i = 1; i <= arrLen; i++) {
            res = (res + dp[steps][i]) % MOD;
        }
        return res;
    }
};
